```python
class Polynome:
    def __init__(self, coeffs):
        self.coeffs = coeffs[:]  # 浅拷贝，避免外部修改

    def __repr__(self):
        terms = []
        for k, c in enumerate(self.coeffs):
            if c == 0: continue
            if k == 0: terms.append(str(c))
            elif k == 1: terms.append(f"{c}*x")
            else: terms.append(f"{c}*x^{k}")
        return " + ".join(terms) if terms else "0"

    def __add__(self, other):
        n = max(len(self.coeffs), len(other.coeffs))
        result = [0] * n
        for i in range(len(self.coeffs)): result[i] += self.coeffs[i]
        for i in range(len(other.coeffs)): result[i] += other.coeffs[i]
        return Polynome(result)

    def __mul__(self, other):
        if not self.coeffs or not other.coeffs: return Polynome([0])
        result = [0] * (len(self.coeffs) + len(other.coeffs) - 1)
        for i, c1 in enumerate(self.coeffs):
            for j, c2 in enumerate(other.coeffs):
                result[i + j] += c1 * c2  # 卷积
        return Polynome(result)

    def derive(self):
        # 导数：系数 [a0, a1, a2, ...] → [a1, 2*a2, 3*a3, ...]
        if len(self.coeffs) <= 1: return Polynome([0])
        return Polynome([self.coeffs[k] * k for k in range(1, len(self.coeffs))])

    def evaluer(self, x):
        result = 0
        for k, c in enumerate(self.coeffs):
            result += c * (x ** k)  # 直接求和法
        return result
```

关键点：
- `__add__`：填充到相同长度，逐项相加
- `__mul__`：卷积（convolution），O(n*m)
- `derive`：移位系数，乘以新的幂次
- `evaluer`：求和法或 Horner 法（后者更快）
- `__repr__`：跳过系数为0的项，格式化输出

